     8→async function chat(message, options = {}) {
     9→  const response = await anthropic.messages.create({
    10→    max_tokens: options.maxTokens || 8192,
    11→    messages: [{ role: 'user', content: message }],
    12→    system: options.system,
    13→  }, {
    14→    headers: options.subscriptionId ? { 'X-Subscription-ID': options.subscriptionId } : {}
    15→  });
    16→  return response.content[0].text;
    17→}
    18→
    19→async function generateInterviewQuestions(jobTitle, jobDescription, count = 5) {
    20→  const prompt = `Generate ${count} interview questions for a ${jobTitle} position.
    21→
    22→Job Description:
    23→${jobDescription || 'General ' + jobTitle + ' role'}
    24→
    25→Return a JSON array with objects containing:
    26→- question: The interview question
    27→- category: behavioral/technical/situational
    28→- difficulty: easy/medium/hard
    29→- key_points: Array of 3-5 key points to look for in a good answer
    30→
    31→Only return the JSON array, no other text.`;
    32→
    33→  const response = await chat(prompt, {
    34→    system: 'You are an expert interviewer. Generate thoughtful, role-specific interview questions. Always return valid JSON.'
    35→  });
    36→
    37→  try {
    38→    return JSON.parse(response);
    39→  } catch (e) {
    40→    const match = response.match(/\[.*\]/s);
    41→    if (match) {
    42→      return JSON.parse(match[0]);
    43→    }
    44→    throw new Error('Failed to parse interview questions');
    45→  }
    46→}
