      <button class="btn btn-ghost btn-large" onclick="closePracticeModal()" style="flex: 1;">
        Close
      </button>
      <button class="btn btn-primary btn-large" onclick="practiceAnother()" style="flex: 1;">
        Practice Another
      </button>
    </div>
  `;

